#include <bits/stdc++.h>
using namespace std;

int n;
double f[9][9][9][9][16],s[9][9];
bool to[9][9][9][9];

double cal(int xl,int yl,int xr,int yr){
    return pow(s[xr][yr]-s[xl-1][yr]-s[xr][yl-1]+s[xl-1][yl-1],2);
}

void dfs(int xl,int yl,int xr,int yr){
    if(to[xl][yl][xr][yr])
        return;
    to[xl][yl][xr][yr]=1;
    for(int i=1;i<16;i++)
        f[xl][yl][xr][yr][i]=1e18;
    f[xl][yl][xr][yr][1]=cal(xl,yl,xr,yr);
    for(int i=2;i<=xr-xl+yr-yl+1;i++){
        for(int j=xl;j<xr;j++){
            dfs(xl,yl,j,yr);
            dfs(j+1,yl,xr,yr);
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][yl][j][yr][i-1]+cal(j+1,yl,xr,yr));
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[j+1][yl][xr][yr][i-1]+cal(xl,yl,j,yr));
        }
        for(int j=yl;j<yr;j++){
            dfs(xl,yl,xr,j);
            dfs(xl,j+1,xr,yr);
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][yl][xr][j][i-1]+cal(xl,j+1,xr,yr));
            f[xl][yl][xr][yr][i]=min(f[xl][yl][xr][yr][i],f[xl][j+1][xr][yr][i-1]+cal(xl,yl,xr,j));
        }
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=8;i++)
        for(int j=1;j<=8;j++){
            scanf("%lf",&s[i][j]);
            s[i][j]+=s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
    dfs(1,1,8,8);
    printf("%.0lf",f[1][1][8][8][n]);
    return 0;
}
